import asyncio
from dataclasses import dataclass, field
from enum import StrEnum

class InterruptType(StrEnum):
    CANCEL   = "cancel"
    PAUSE    = "pause"
    REDIRECT = "redirect"
    INJECT   = "inject"

@dataclass
class InterruptToken:
    _cancel_event: asyncio.Event = field(default_factory=asyncio.Event)
    _pause_event:  asyncio.Event = field(default_factory=asyncio.Event)
    _inject_queue: asyncio.Queue = field(default_factory=asyncio.Queue)
    redirect_goal: str | None = None

    def cancel(self):
        self._cancel_event.set()

    def pause(self):
        self._pause_event.set()

    def resume(self):
        self._pause_event.clear()

    def inject(self, message: str):
        self._inject_queue.put_nowait(message)

    def redirect(self, new_goal: str):
        self.redirect_goal = new_goal

    @property
    def is_cancelled(self) -> bool:
        return self._cancel_event.is_set()

    @property
    def is_paused(self) -> bool:
        return self._pause_event.is_set()

    def drain_injections(self) -> list[str]:
        msgs = []
        while not self._inject_queue.empty():
            msgs.append(self._inject_queue.get_nowait())
        return msgs

import anthropic

client = anthropic.Anthropic()

class AgentInterrupted(Exception):
    pass

class AgentPaused(Exception):
    def __init__(self, state: dict):
        self.state = state

async def run_interruptible_agent(
    system: str,
    messages: list[dict],
    tools: list[dict],
    token: InterruptToken,
    max_iters: int = 30,
) -> str:
    for iteration in range(max_iters):
        # --- Checkpoint 1: check cancel before model call ---
        if token.is_cancelled:
            raise AgentInterrupted("Agent cancelled before model call")

        # --- Checkpoint 2: handle pause (block until resumed or cancelled) ---
        while token.is_paused:
            if token.is_cancelled:
                raise AgentInterrupted("Agent cancelled while paused")
            await asyncio.sleep(0.5)

        # --- Checkpoint 3: handle injected messages ---
        injected = token.drain_injections()
        for msg in injected:
            messages = messages + [{"role": "user", "content": msg}]

        # --- Checkpoint 4: handle goal redirect ---
        if token.redirect_goal:
            new_goal = token.redirect_goal
            token.redirect_goal = None
            messages = messages + [{
                "role": "user",
                "content": f"[REDIRECT] New goal: {new_goal}",
            }]

        # Model call (may take seconds — cannot be interrupted mid-stream)
        resp = client.messages.create(
            model="claude-opus-4-8",
            max_tokens=4096,
            system=system,
            messages=messages,
            tools=tools,
        )

        # --- Checkpoint 5: check cancel after model call returns ---
        if token.is_cancelled:
            raise AgentInterrupted("Agent cancelled after model call")

        if resp.stop_reason == "end_turn":
            return " ".join(b.text for b in resp.content if hasattr(b, "text"))

        tool_results = []
        for block in resp.content:
            if block.type != "tool_use":
                continue
            # --- Checkpoint 6: check cancel before each tool call ---
            if token.is_cancelled:
                raise AgentInterrupted(f"Agent cancelled before tool: {block.name}")
            result = await _execute_tool(block.name, block.input)
            tool_results.append({
                "type": "tool_result",
                "tool_use_id": block.id,
                "content": result,
            })

        messages = messages + [
            {"role": "assistant", "content": resp.content},
            {"role": "user", "content": tool_results},
        ]

    return "max_iterations reached"

from fastapi import FastAPI, HTTPException
from pydantic import BaseModel

app = FastAPI()
_tokens: dict[str, InterruptToken] = {}

def register_agent(agent_id: str) -> InterruptToken:
    token = InterruptToken()
    _tokens[agent_id] = token
    return token

class InjectBody(BaseModel):
    message: str

class RedirectBody(BaseModel):
    new_goal: str

@app.post("/agents/{agent_id}/cancel")
def cancel_agent(agent_id: str):
    token = _tokens.get(agent_id)
    if not token:
        raise HTTPException(404, "Agent not found")
    token.cancel()
    return {"status": "cancel signal sent"}

@app.post("/agents/{agent_id}/pause")
def pause_agent(agent_id: str):
    token = _tokens.get(agent_id)
    if not token:
        raise HTTPException(404, "Agent not found")
    token.pause()
    return {"status": "pause signal sent"}

@app.post("/agents/{agent_id}/resume")
def resume_agent(agent_id: str):
    token = _tokens.get(agent_id)
    if not token:
        raise HTTPException(404, "Agent not found")
    token.resume()
    return {"status": "resume signal sent"}

@app.post("/agents/{agent_id}/inject")
def inject_message(agent_id: str, body: InjectBody):
    token = _tokens.get(agent_id)
    if not token:
        raise HTTPException(404, "Agent not found")
    token.inject(body.message)
    return {"status": "message injected"}

@app.post("/agents/{agent_id}/redirect")
def redirect_agent(agent_id: str, body: RedirectBody):
    token = _tokens.get(agent_id)
    if not token:
        raise HTTPException(404, "Agent not found")
    token.redirect(body.new_goal)
    return {"status": "redirect signal sent"}

class OrchestratorToken:
    def __init__(self):
        self._child_tokens: list[InterruptToken] = []
        self._own_token = InterruptToken()

    def spawn_child_token(self) -> InterruptToken:
        child = InterruptToken()
        self._child_tokens.append(child)
        return child

    def cancel_all(self):
        self._own_token.cancel()
        for child in self._child_tokens:
            child.cancel()

    def pause_all(self):
        self._own_token.pause()
        for child in self._child_tokens:
            child.pause()

    def resume_all(self):
        self._own_token.resume()
        for child in self._child_tokens:
            child.resume()

    @property
    def is_cancelled(self) -> bool:
        return self._own_token.is_cancelled
